/* Read-repair + asynchronous fix (pseudo-JS) */
async function getWithReadRepair(key, replicas) {
  const responses = await Promise.all(replicas.map(r => r.get(key)));
  // responses: [{value, ts, replica}...]
  const best = responses.reduce((a,b) => a.ts >= b.ts ? a : b);
  // Fire-and-forget repairs for outdated replicas
  responses.forEach(r => {
    if (r.value !== best.value) {
      r.replica.write(key, best.value).catch(console.warn);
    }
  });
  return best.value;
}

